186: 	private wrapTextDocumentLine(document: TextDocument, line: number): string[] {
187: 		const config = workspace.getConfiguration('git');
188: 		const inputValidationLength = config.get<number>('inputValidationLength', 50);
189: 		const inputValidationSubjectLength = config.get<number | undefined>('inputValidationSubjectLength', undefined);
190: 		const lineLengthThreshold = line === 0 ? inputValidationSubjectLength ?? inputValidationLength : inputValidationLength;
191: 
192: 		const lineSegments: string[] = [];
193: 		const lineText = document.lineAt(line).text.trim();
194: 
195: 		let position = 0;
196: 		while (lineText.length - position > lineLengthThreshold) {
197: 			const lastSpaceBeforeThreshold = lineText.lastIndexOf(' ', position + lineLengthThreshold);
198: 
199: 			if (lastSpaceBeforeThreshold !== -1 && lastSpaceBeforeThreshold > position) {
200: 				lineSegments.push(lineText.substring(position, lastSpaceBeforeThreshold));
201: 				position = lastSpaceBeforeThreshold + 1;
202: 			} else {
203: 				// Find first space after threshold
204: 				const firstSpaceAfterThreshold = lineText.indexOf(' ', position + lineLengthThreshold);
205: 				if (firstSpaceAfterThreshold !== -1) {
206: 					lineSegments.push(lineText.substring(position, firstSpaceAfterThreshold));
207: 					position = firstSpaceAfterThreshold + 1;
208: 				} else {
209: 					lineSegments.push(lineText.substring(position));
210: 					position = lineText.length;
211: 				}
212: 			}
213: 		}
214: 		if (position < lineText.length) {
215: 			lineSegments.push(lineText.substring(position));
216: 		}
217: 
218: 		return lineSegments;
219: 	}
